190→export function buildWallDimensionFigures(walls = [], columns = []) {
191→  const faces = detectRoomFaces(walls, columns || []);
192→
193→  return walls
194→    .map((wall) => {
195→      const renderWall = getWallRenderData(wall, columns || []).renderWall;
196→      return pickWallDimensionFigure(renderWall, faces, wall.id);
197→    })
198→    .filter(Boolean);
199→}
