201→export function buildRoomDimensionFigures(rooms = []) {
202→  const figures = [];
203→
204→  for (const room of rooms) {
205→    if (!room.points?.length) continue;
206→
207→    const xs = room.points.map((point) => point.x);
208→    const ys = room.points.map((point) => point.y);
209→    const minX = Math.min(...xs);
210→    const maxX = Math.max(...xs);
211→    const minY = Math.min(...ys);
212→    const maxY = Math.max(...ys);
213→
214→    const horizontal = createDimensionFigure({
215→      id: `room-dim-h-${room.id}`,
216→      startPoint: { x: minX, y: minY },
217→      endPoint: { x: maxX, y: minY },
218→      mode: 'horizontal',
219→      offset: ROOM_DIMENSION_INSET,
220→      source: 'derived',
221→      sourceType: 'room',
222→      sourceId: room.id,
223→    });
224→
225→    const vertical = createDimensionFigure({
226→      id: `room-dim-v-${room.id}`,
227→      startPoint: { x: maxX, y: minY },
228→      endPoint: { x: maxX, y: maxY },
229→      mode: 'vertical',
230→      offset: -ROOM_DIMENSION_INSET,
231→      source: 'derived',
232→      sourceType: 'room',
233→      sourceId: room.id,
234→    });
235→
236→    if (horizontal) figures.push(horizontal);
237→    if (vertical) figures.push(vertical);
238→  }
239→
240→  return figures;
241→}
242→
243→function uniqueSortedValues(values = []) {
244→  const sorted = [...values].sort((a, b) => a - b);
245→  return sorted.filter((value, index) => (
246→    index === 0 || Math.abs(value - sorted[index - 1]) > VALUE_MERGE_TOLERANCE
247→  ));
248→}
249→
250→export function buildOverallDimensionFigures(walls = [], columns = []) {
251→  const renderWalls = walls
252→    .map((wall) => getWallRenderData(wall, columns || []).renderWall)
253→    .filter(Boolean);
254→
255→  const points = renderWalls.flatMap((wall) => [wall.start, wall.end]);
256→  if (points.length < 2) return [];
257→
258→  const xs = points.map((point) => point.x);
259→  const ys = points.map((point) => point.y);
260→  const minX = Math.min(...xs);
261→  const maxX = Math.max(...xs);
262→  const minY = Math.min(...ys);
263→  const maxY = Math.max(...ys);
264→  const chainX = uniqueSortedValues(xs);
265→  const chainY = uniqueSortedValues(ys);
266→  const figures = [];
267→
268→  for (let index = 0; index < chainX.length - 1; index += 1) {
269→    const figure = createDimensionFigure({
270→      id: `overall-chain-x-${index}`,
271→      startPoint: { x: chainX[index], y: minY },
272→      endPoint: { x: chainX[index + 1], y: minY },
273→      mode: 'horizontal',
274→      offset: -OVERALL_CHAIN_GAP,
275→      source: 'derived',
276→      sourceType: 'overall-chain',
277→    });
278→    if (figure) figures.push(figure);
279→  }
280→
281→  for (let index = 0; index < chainY.length - 1; index += 1) {
282→    const figure = createDimensionFigure({
283→      id: `overall-chain-y-${index}`,
284→      startPoint: { x: minX, y: chainY[index] },
285→      endPoint: { x: minX, y: chainY[index + 1] },
286→      mode: 'vertical',
287→      offset: -OVERALL_CHAIN_GAP,
288→      source: 'derived',
289→      sourceType: 'overall-chain',
290→    });
291→    if (figure) figures.push(figure);
292→  }
293→
294→  const overallWidth = createDimensionFigure({
295→    id: 'overall-width',
296→    startPoint: { x: minX, y: minY },
297→    endPoint: { x: maxX, y: minY },
298→    mode: 'horizontal',
299→    offset: -OVERALL_TOTAL_GAP,
300→    source: 'derived',
301→    sourceType: 'overall',
302→  });
303→
304→  const overallHeight = createDimensionFigure({
305→    id: 'overall-height',
306→    startPoint: { x: minX, y: minY },
307→    endPoint: { x: minX, y: maxY },
308→    mode: 'vertical',
309→    offset: -OVERALL_TOTAL_GAP,
310→    source: 'derived',
311→    sourceType: 'overall',
312→  });
313→
314→  if (overallWidth) figures.push(overallWidth);
315→  if (overallHeight) figures.push(overallHeight);
316→
317→  return figures;
318→}
