 1→import { DIMENSION_DEFAULT_OFFSET, GRID_MINOR } from '@/domain/defaults';
 2→import { createLinearDimensionAnnotation } from '@/domain/models';
 3→import { distance } from '@/geometry/point';
 4→
 5→function snapToGrid(value) {
 6→  return Math.round(value / GRID_MINOR) * GRID_MINOR;
 7→}
 8→
 9→function resolvePoint(modelPos, snapEnabled) {
10→  if (!snapEnabled) return { x: modelPos.x, y: modelPos.y };
11→  return {
12→    x: snapToGrid(modelPos.x),
13→    y: snapToGrid(modelPos.y),
14→  };
15→}
16→
17→function resetDimensionTool(editorDispatch) {
18→  editorDispatch({
19→    type: 'UPDATE_TOOL_STATE',
20→    payload: {
21→      dimensionStartPoint: null,
22→      dimensionPreviewPoint: null,
23→      dimensionPreviewOffset: null,
24→    },
25→  });
26→}
27→
28→export function createDimensionPlaceHandler({ dispatch, editorDispatch, activeFloorId, snapEnabled }) {
29→  return {
30→    onMouseDown(modelPos, e, toolState) {
31→      if (e.button !== 0) return;
32→
33→      const point = resolvePoint(modelPos, snapEnabled);
34→      if (!toolState.dimensionStartPoint) {
35→        editorDispatch({
36→          type: 'UPDATE_TOOL_STATE',
37→          payload: {
38→            dimensionStartPoint: point,
39→            dimensionPreviewPoint: point,
40→            dimensionPreviewOffset: DIMENSION_DEFAULT_OFFSET,
41→          },
42→        });
43→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Click the end point for the dimension.' });
44→        return;
45→      }
46→
47→      if (distance(toolState.dimensionStartPoint, point) < GRID_MINOR / 2) {
48→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Choose a different end point for the dimension.' });
49→        return;
50→      }
51→
52→      const annotation = createLinearDimensionAnnotation(
53→        toolState.dimensionStartPoint,
54→        point,
55→        {
56→          mode: 'aligned',
57→          offset: toolState.dimensionPreviewOffset ?? DIMENSION_DEFAULT_OFFSET,
58→        }
59→      );
60→
61→      dispatch({ type: 'ANNOTATION_ADD', floorId: activeFloorId, annotation });
62→      editorDispatch({ type: 'SELECT_OBJECT', id: annotation.id, objectType: 'annotation' });
63→      resetDimensionTool(editorDispatch);
64→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Dimension created.' });
65→    },
66→
67→    onMouseMove(modelPos, e, toolState) {
68→      if (!toolState.dimensionStartPoint) return;
69→
70→      const point = resolvePoint(modelPos, snapEnabled);
71→      editorDispatch({
72→        type: 'UPDATE_TOOL_STATE',
73→        payload: {
74→          dimensionPreviewPoint: point,
75→          dimensionPreviewOffset: DIMENSION_DEFAULT_OFFSET,
76→        },
77→      });
78→    },
79→
80→    onKeyDown(e) {
81→      if (e.key !== 'Escape') return;
82→      resetDimensionTool(editorDispatch);
83→      editorDispatch({ type: 'SET_TOOL', tool: 'select' });
84→    },
85→
86→    getCursor() {
87→      return 'crosshair';
88→    },
89→  };
90→}
