  1→import { useRef, useCallback, useEffect, useState } from 'react';
  2→import { useEditor } from '@/app/EditorProvider';
  3→import { useProject } from '@/app/ProjectProvider';
  4→import { useEditorTool } from '@/editor/useEditorTool';
  5→import { MIN_ZOOM, MAX_ZOOM, ZOOM_FACTOR } from '@/domain/defaults';
  6→import { TOOLS } from '@/editor/tools';
  7→import GridRenderer from './GridRenderer';
  8→import SlabRenderer from './SlabRenderer';
  9→import WallRenderer from './WallRenderer';
 10→import BeamRenderer from './BeamRenderer';
 11→import StairRenderer from './StairRenderer';
 12→import DoorRenderer from './DoorRenderer';
 13→import WindowRenderer from './WindowRenderer';
 14→import RoomRenderer from './RoomRenderer';
 15→import AnnotationRenderer from './AnnotationRenderer';
 16→import ElevationRenderer from './ElevationRenderer';
 17→import SelectionOverlay from './SelectionOverlay';
 18→import DimensionPreview from './DimensionPreview';
 19→import WallPreview from './WallPreview';
 20→import ColumnRenderer from './ColumnRenderer';
 21→import ColumnPreview from './ColumnPreview';
 22→import BeamPreview from './BeamPreview';
 23→import StairPreview from './StairPreview';
 24→import SlabPreview from './SlabPreview';
 25→import DoorWindowPreview from './DoorWindowPreview';
 26→import RoomPreview from './RoomPreview';
 27→import { isTypingTarget } from '@/utils/keyboard';
 28→import styles from './SvgCanvas.module.css';
 29→
 30→function screenToModel(screenX, screenY, viewport, svgRect) {
 31→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 32→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 33→  return { x, y };
 34→}
 35→
 36→export default function SvgCanvas() {
 37→  const svgRef = useRef(null);
 38→  const isPanning = useRef(false);
 39→  const lastPanPos = useRef({ x: 0, y: 0 });
 40→  const spaceHeld = useRef(false);
 41→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 42→
 43→  const { project, dispatch, getFloor } = useProject();
 44→  const editor = useEditor();
 45→  const {
 46→    activeTool, selectedId, selectedType, toolState,
 47→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode,
 48→    dispatch: editorDispatch,
 49→  } = editor;
 50→
 51→  const floor = getFloor(activeFloorId);
 52→
 53→  const tool = useEditorTool({
 54→    activeTool,
 55→    dispatch,
 56→    editorDispatch,
 57→    getFloor,
 58→    activeFloorId,
 59→    viewport,
 60→    snapEnabled,
 61→    selectedId,
 62→    selectedType,
 63→    toolState,
 64→    viewMode,
 65→  });
 66→
 67→  const getModelPos = useCallback((e) => {
 68→    const rect = svgRef.current.getBoundingClientRect();
 69→    return screenToModel(e.clientX, e.clientY, viewport, rect);
 70→  }, [viewport]);
 71→
 72→  const handleMouseDown = useCallback((e) => {
 73→    // Middle mouse or space+left for pan
 74→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
 75→      isPanning.current = true;
 76→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 77→      e.preventDefault();
 78→      return;
 79→    }
 80→
 81→    const modelPos = getModelPos(e);
 82→    tool.onMouseDown(modelPos, e);
 83→  }, [getModelPos, tool]);
 84→
 85→  const handleMouseMove = useCallback((e) => {
 86→    if (isPanning.current) {
 87→      const dx = e.clientX - lastPanPos.current.x;
 88→      const dy = e.clientY - lastPanPos.current.y;
 89→      editorDispatch({ type: 'PAN', dx, dy });
 90→      lastPanPos.current = { x: e.clientX, y: e.clientY };
 91→      return;
 92→    }
 93→
 94→    const modelPos = getModelPos(e);
 95→    setCursorPos(modelPos);
 96→    tool.onMouseMove(modelPos, e);
 97→  }, [getModelPos, tool, editorDispatch]);
 98→
 99→  const handleMouseUp = useCallback((e) => {
100→    if (isPanning.current) {
101→      isPanning.current = false;
102→      return;
103→    }
104→    const modelPos = getModelPos(e);
105→    tool.onMouseUp(modelPos, e);
106→  }, [getModelPos, tool]);
107→
108→  const handleDoubleClick = useCallback((e) => {
109→    const modelPos = getModelPos(e);
110→    tool.onDoubleClick(modelPos, e);
111→  }, [getModelPos, tool]);
112→
113→  const handleWheel = useCallback((e) => {
114→    e.preventDefault();
115→    const rect = svgRef.current.getBoundingClientRect();
116→    const mouseX = e.clientX - rect.left;
117→    const mouseY = e.clientY - rect.top;
118→
119→    const direction = e.deltaY < 0 ? 1 : -1;
120→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
121→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
122→
123→    // Zoom centered on cursor
124→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
125→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
126→
127→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
128→  }, [viewport, editorDispatch]);
129→
130→  useEffect(() => {
131→    if (!statusMessage) return undefined;
132→
133→    const timer = window.setTimeout(() => {
134→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
135→    }, 2500);
136→
137→    return () => window.clearTimeout(timer);
138→  }, [statusMessage, editorDispatch]);
139→
140→  useEffect(() => {
141→    const handleKeyDown = (e) => {
142→      if (isTypingTarget(e.target)) return;
143→
144→      if (e.key === ' ') {
145→        spaceHeld.current = true;
146→        e.preventDefault();
147→      }
148→
149→      // Tool shortcuts
150→      if (viewMode === 'plan' && !e.ctrlKey && !e.metaKey) {
151→        switch (e.key.toLowerCase()) {
152→          case 'v':
153→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
154→            return;
155→          case 'm':
156→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
157→            return;
158→          case 'w':
159→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
160→            return;
161→          case 'b':
162→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
163→            return;
164→          case 't':
165→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
166→            return;
167→          case 's':
168→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
169→            return;
170→          case 'r':
171→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
172→            return;
173→          case 'd':
174→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
175→            return;
176→          case 'n':
177→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
178→            return;
179→          case 'c':
180→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
181→            return;
182→        }
183→      }
184→
185→      tool.onKeyDown(e);
186→    };
187→
188→    const handleKeyUp = (e) => {
189→      if (isTypingTarget(e.target)) return;
190→
191→      if (e.key === ' ') {
192→        spaceHeld.current = false;
193→      }
194→    };
195→
196→    window.addEventListener('keydown', handleKeyDown);
197→    window.addEventListener('keyup', handleKeyUp);
198→    return () => {
199→      window.removeEventListener('keydown', handleKeyDown);
200→      window.removeEventListener('keyup', handleKeyUp);
201→    };
202→  }, [tool, editorDispatch, viewMode]);
203→
204→  // Prevent default context menu on SVG
205→  useEffect(() => {
206→    const svg = svgRef.current;
207→    if (!svg) return;
208→    const prevent = (e) => e.preventDefault();
209→    svg.addEventListener('contextmenu', prevent);
210→    svg.addEventListener('wheel', handleWheel, { passive: false });
211→    return () => {
212→      svg.removeEventListener('contextmenu', prevent);
213→      svg.removeEventListener('wheel', handleWheel);
214→    };
215→  }, [handleWheel]);
216→
217→  const cursor = spaceHeld.current ? 'grab' : tool.getCursor();
218→  const zoomPercent = Math.round(viewport.zoom * 1000);
219→
220→  return (
221→    <div className={styles.canvasContainer}>
222→      <svg
223→        ref={svgRef}
224→        className={styles.svg}
225→        style={{ cursor }}
226→        onMouseDown={handleMouseDown}
227→        onMouseMove={handleMouseMove}
228→        onMouseUp={handleMouseUp}
229→        onDoubleClick={handleDoubleClick}
230→      >
231→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
232→          {viewMode === 'plan' && showGrid && <GridRenderer />}
233→          {viewMode === 'plan' && showGrid && (
234→            <rect
235→              x={-100000} y={-100000}
236→              width={200000} height={200000}
237→              fill="url(#grid-major)"
238→              style={{ pointerEvents: 'none' }}
239→            />
240→          )}
241→          {floor && (
242→            viewMode === 'plan' ? (
243→              <>
244→                <SlabRenderer slab={floor.slab} selectedId={selectedId} />
245→                <RoomRenderer rooms={floor.rooms} selectedId={selectedId} />
246→                <RoomPreview toolState={toolState} activeTool={activeTool} />
247→                <WallRenderer walls={floor.walls} columns={floor.columns || []} />
248→                <BeamRenderer beams={floor.beams || []} columns={floor.columns || []} />
249→                <StairRenderer stairs={floor.stairs || []} />
250→                <ColumnRenderer columns={floor.columns || []} />
251→                <DoorRenderer doors={floor.doors} walls={floor.walls} />
252→                <WindowRenderer windows={floor.windows} walls={floor.walls} />
253→                <AnnotationRenderer floor={floor} />
254→                <SelectionOverlay
255→                  selectedId={selectedId}
256→                  selectedType={selectedType}
257→                  floor={floor}
258→                  zoom={viewport.zoom}
259→                />
260→                <DimensionPreview toolState={toolState} activeTool={activeTool} />
261→                <WallPreview toolState={toolState} activeTool={activeTool} />
262→                <SlabPreview toolState={toolState} activeTool={activeTool} />
263→                <BeamPreview
264→                  toolState={toolState}
265→                  activeTool={activeTool}
266→                  columns={floor.columns || []}
267→                  floorLevel={floor.level}
268→                />
269→                <StairPreview
270→                  toolState={toolState}
271→                  activeTool={activeTool}
272→                  floorId={floor.id}
273→                />
274→                <DoorWindowPreview
275→                  toolState={toolState}
276→                  activeTool={activeTool}
277→                  walls={floor.walls}
278→                />
279→                <ColumnPreview toolState={toolState} activeTool={activeTool} />
280→              </>
281→            ) : (
282→              <ElevationRenderer floor={floor} viewMode={viewMode} />
283→            )
284→          )}
285→        </g>
286→      </svg>
287→      <div className={styles.statusBar}>
288→        <span>X: {Math.round(cursorPos.x)} mm</span>
289→        <span>Y: {Math.round(cursorPos.y)} mm</span>
290→        <span>Zoom: {zoomPercent}%</span>
291→        <span>View: {viewMode}</span>
292→        <span>Tool: {activeTool}</span>
293→        {statusMessage && <span className={styles.statusMessage}>{statusMessage}</span>}
294→      </div>
295→    </div>
296→  );
297→}
