 1→import { subtract, dot, add, scale, distance } from './point';
 2→
 3→export function nearestPointOnSegment(p, a, b) {
 4→  const ab = subtract(b, a);
 5→  const ap = subtract(p, a);
 6→  const lenSq = dot(ab, ab);
 7→  if (lenSq === 0) return { point: { ...a }, t: 0 };
 8→  let t = dot(ap, ab) / lenSq;
 9→  t = Math.max(0, Math.min(1, t));
10→  return {
11→    point: add(a, scale(ab, t)),
12→    t,
13→  };
14→}
15→
16→export function distanceToSegment(p, a, b) {
17→  const { point } = nearestPointOnSegment(p, a, b);
18→  return distance(p, point);
19→}
20→
21→export function segmentLength(a, b) {
22→  return distance(a, b);
23→}
24→
25→export function segmentIntersection(a1, a2, b1, b2) {
26→  const d1 = subtract(a2, a1);
27→  const d2 = subtract(b2, b1);
28→  const cross = d1.x * d2.y - d1.y * d2.x;
29→  if (Math.abs(cross) < 1e-10) return null;
30→
31→  const d = subtract(b1, a1);
32→  const t = (d.x * d2.y - d.y * d2.x) / cross;
33→  const u = (d.x * d1.y - d.y * d1.x) / cross;
34→
35→  if (t >= 0 && t <= 1 && u >= 0 && u <= 1) {
36→    return add(a1, scale(d1, t));
37→  }
38→  return null;
39→}
40→

 1→export function distance(a, b) {
 2→  const dx = b.x - a.x;
 3→  const dy = b.y - a.y;
 4→  return Math.sqrt(dx * dx + dy * dy);
 5→}
 6→
 7→export function midpoint(a, b) {
 8→  return { x: (a.x + b.x) / 2, y: (a.y + b.y) / 2 };
 9→}
10→
11→export function lerp(a, b, t) {
12→  return { x: a.x + (b.x - a.x) * t, y: a.y + (b.y - a.y) * t };
13→}
14→
15→export function rotate(point, center, angleDeg) {
16→  const rad = (angleDeg * Math.PI) / 180;
17→  const cos = Math.cos(rad);
18→  const sin = Math.sin(rad);
19→  const dx = point.x - center.x;
20→  const dy = point.y - center.y;
21→  return {
22→    x: center.x + dx * cos - dy * sin,
23→    y: center.y + dx * sin + dy * cos,
24→  };
25→}
26→
27→export function add(a, b) {
28→  return { x: a.x + b.x, y: a.y + b.y };
29→}
30→
31→export function subtract(a, b) {
32→  return { x: a.x - b.x, y: a.y - b.y };
33→}
34→
35→export function scale(p, s) {
36→  return { x: p.x * s, y: p.y * s };
37→}
38→
39→export function normalize(p) {
40→  const len = Math.sqrt(p.x * p.x + p.y * p.y);
41→  if (len === 0) return { x: 0, y: 0 };
42→  return { x: p.x / len, y: p.y / len };
43→}
44→
45→export function perpendicular(p) {
46→  return { x: -p.y, y: p.x };
47→}
48→
49→export function dot(a, b) {
50→  return a.x * b.x + a.y * b.y;
51→}
