 1→import { TOOLS } from '@/editor/tools';
 2→import { positionOnWall, wallDirection } from '@/geometry/wallGeometry';
 3→import { perpendicular, scale, add } from '@/geometry/point';
 4→import { DOOR_WIDTH, WINDOW_WIDTH } from '@/domain/defaults';
 5→
 6→export default function DoorWindowPreview({ toolState, activeTool, walls }) {
 7→  if (activeTool !== TOOLS.DOOR && activeTool !== TOOLS.WINDOW) return null;
 8→  if (!toolState.previewWallId || toolState.previewOffset == null) return null;
 9→
10→  const wall = walls.find(w => w.id === toolState.previewWallId);
11→  if (!wall) return null;
12→
13→  const width = activeTool === TOOLS.DOOR ? DOOR_WIDTH : WINDOW_WIDTH;
14→  const center = positionOnWall(wall, toolState.previewOffset);
15→  const dir = wallDirection(wall);
16→  const perp = perpendicular(dir);
17→  const halfThick = wall.thickness / 2;
18→  const halfWidth = width / 2;
19→
20→  const p1 = add(add(center, scale(dir, -halfWidth)), scale(perp, halfThick));
21→  const p2 = add(add(center, scale(dir, halfWidth)), scale(perp, halfThick));
22→  const p3 = add(add(center, scale(dir, halfWidth)), scale(perp, -halfThick));
23→  const p4 = add(add(center, scale(dir, -halfWidth)), scale(perp, -halfThick));
24→
25→  return (
26→    <polygon
27→      points={`${p1.x},${p1.y} ${p2.x},${p2.y} ${p3.x},${p3.y} ${p4.x},${p4.y}`}
28→      fill="rgba(43, 127, 255, 0.2)"
29→      stroke="var(--color-selection)"
30→      strokeWidth={2}
31→      strokeDasharray="4 2"
32→      vectorEffect="non-scaling-stroke"
33→      style={{ pointerEvents: 'none' }}
34→    />
35→  );
