  1→import { add, subtract, scale, dot, normalize, perpendicular, distance } from './point';
  2→import { nearestPointOnSegment } from './line';
  3→import { columnOutline, columnFaces, columnCenterlines, columnCenter, columnAxes } from './columnGeometry';
  4→
  5→const EPSILON = 1e-6;
  6→const CENTERLINE_ALIGNMENT_THRESHOLD = 0.92;
  7→
  8→function makeOutline(start, end, thickness) {
  9→  const dir = normalize(subtract(end, start));
 10→  const perp = perpendicular(dir);
 11→  const halfThick = thickness / 2;
 12→  const offset = scale(perp, halfThick);
 13→
 14→  return [
 15→    add(start, offset),
 16→    add(end, offset),
 17→    subtract(end, offset),
 18→    subtract(start, offset),
 19→  ];
 20→}
 21→
 22→function findColumn(columns, columnId) {
 23→  return (columns || []).find((column) => column.id === columnId) || null;
 24→}
 25→
 26→function raySegmentIntersection(origin, direction, start, end) {
 27→  const segment = subtract(end, start);
 28→  const cross = direction.x * segment.y - direction.y * segment.x;
 29→
 30→  if (Math.abs(cross) < EPSILON) return null;
 31→
 32→  const delta = subtract(start, origin);
 33→  const t = (delta.x * segment.y - delta.y * segment.x) / cross;
 34→  const u = (delta.x * direction.y - delta.y * direction.x) / cross;
 35→
 36→  if (t < -EPSILON || u < -EPSILON || u > 1 + EPSILON) return null;
 37→
 38→  return {
 39→    t,
 40→    point: add(origin, scale(direction, Math.max(0, t))),
 41→  };
 42→}
 43→
 44→function findTrimPoint(origin, otherPoint, attachment, columns) {
 45→  if (!attachment?.columnId) return { ...origin };
 46→
 47→  const column = findColumn(columns, attachment.columnId);
 48→  if (!column) return { ...origin };
 49→
 50→  const direction = normalize(subtract(otherPoint, origin));
 51→  if (Math.abs(direction.x) < EPSILON && Math.abs(direction.y) < EPSILON) {
 52→    return { ...origin };
 53→  }
 54→
 55→  const polygon = columnOutline(column);
 56→  let best = null;
 57→
 58→  for (let i = 0; i < polygon.length; i += 1) {
 59→    const hit = raySegmentIntersection(origin, direction, polygon[i], polygon[(i + 1) % polygon.length]);
 60→    if (!hit) continue;
 61→    if (!best || hit.t < best.t) {
 62→      best = hit;
 63→    }
 64→  }
 65→
 66→  return best ? best.point : { ...origin };
 67→}
 68→
 69→function cloneAttachment(attachment) {
 70→  return attachment ? { ...attachment } : null;
 71→}
 72→
 73→function rankCandidate(current, candidate) {
 74→  if (!current) return true;
 75→  if (candidate.priority !== current.priority) return candidate.priority < current.priority;
 76→  return candidate.distance < current.distance;
 77→}
 78→
 79→function setBestCandidate(best, candidate) {
 80→  if (!candidate) return best;
 81→  if (!rankCandidate(best, candidate)) return best;
 82→  return candidate;
 83→}
 84→
 85→function buildFaceAttachment(column, face, point) {
 86→  const offset = dot(subtract(point, face.midpoint), face.tangent);
 87→  return {
 88→    kind: 'column',
 89→    columnId: column.id,
 90→    featureType: 'face',
 91→    featureIndex: face.index,
 92→    offset,
 93→  };
 94→}
 95→
 96→function buildCenterlineAttachment(column, centerline, point) {
 97→  const center = columnCenter(column);
 98→  return {
 99→    kind: 'column',
100→    columnId: column.id,
101→    featureType: 'centerline',
102→    featureIndex: centerline.index,
103→    offset: dot(subtract(point, center), centerline.axis),
104→  };
105→}
106→
107→export function resolveColumnAttachmentPoint(column, attachment) {
108→  if (!column || !attachment) return null;
109→
110→  if (attachment.featureType === 'corner') {
111→    const corners = columnOutline(column);
112→    return corners[attachment.featureIndex] ? { ...corners[attachment.featureIndex] } : null;
113→  }
114→
115→  if (attachment.featureType === 'face') {
116→    const face = columnFaces(column).find((entry) => entry.index === attachment.featureIndex);
117→    if (!face) return null;
118→    const clamped = Math.max(-face.length / 2, Math.min(face.length / 2, attachment.offset || 0));
119→    return add(face.midpoint, scale(face.tangent, clamped));
120→  }
121→
122→  if (attachment.featureType === 'centerline') {
123→    const centerline = columnCenterlines(column).find((entry) => entry.index === attachment.featureIndex);
124→    if (!centerline) return null;
125→    return add(columnCenter(column), scale(centerline.axis, attachment.offset || 0));
126→  }
127→
128→  return null;
129→}
130→
131→export function syncWallAttachmentPoints(wall, columns = []) {
132→  let nextWall = { ...wall };
133→
134→  for (const endpoint of ['start', 'end']) {
135→    const attachmentKey = `${endpoint}Attachment`;
136→    const attachment = nextWall[attachmentKey];
137→    if (!attachment) continue;
138→
139→    const column = findColumn(columns, attachment.columnId);
140→    if (!column) {
141→      nextWall = { ...nextWall, [attachmentKey]: null };
142→      continue;
143→    }
144→
145→    const point = resolveColumnAttachmentPoint(column, attachment);
146→    if (!point) {
147→      nextWall = { ...nextWall, [attachmentKey]: null };
148→      continue;
149→    }
150→
151→    nextWall = {
152→      ...nextWall,
153→      [endpoint]: point,
154→      [attachmentKey]: cloneAttachment(attachment),
155→    };
156→  }
157→
158→  return nextWall;
159→}
160→
161→export function detachColumnAttachments(wall, columns = [], columnId) {
162→  const syncedWall = syncWallAttachmentPoints(wall, columns);
163→  let nextWall = syncedWall;
164→
165→  for (const endpoint of ['start', 'end']) {
166→    const attachmentKey = `${endpoint}Attachment`;
167→    if (nextWall[attachmentKey]?.columnId !== columnId) continue;
168→    nextWall = {
169→      ...nextWall,
170→      [attachmentKey]: null,
171→    };
172→  }
173→
174→  return nextWall;
175→}
176→
177→export function getWallRenderData(wall, columns = []) {
178→  const syncedWall = syncWallAttachmentPoints(wall, columns);
179→  const trimStart = findTrimPoint(syncedWall.start, syncedWall.end, syncedWall.startAttachment, columns);
180→  const trimEnd = findTrimPoint(syncedWall.end, syncedWall.start, syncedWall.endAttachment, columns);
181→  const outline = makeOutline(trimStart, trimEnd, syncedWall.thickness);
182→
183→  return {
184→    wall: syncedWall,
185→    renderWall: {
186→      ...syncedWall,
187→      start: trimStart,
188→      end: trimEnd,
189→    },
190→    outline,
191→    trimStart,
192→    trimEnd,
193→  };
194→}
195→
196→export function snapWallEndpoint(modelPos, {
197→  walls = [],
198→  columns = [],
199→  snapDist,
200→  chainStart = null,
201→  otherPoint = null,
202→  ignoreWallId = null,
203→} = {}) {
204→  let best = null;
205→  const directionHint = otherPoint && distance(otherPoint, modelPos) > EPSILON
206→    ? normalize(subtract(modelPos, otherPoint))
207→    : null;
208→
209→  const consider = (point, priority, attachment = null) => {
210→    const candidateDistance = distance(modelPos, point);
211→    if (candidateDistance > snapDist) return;
212→    best = setBestCandidate(best, {
213→      point: { x: point.x, y: point.y },
214→      attachment: cloneAttachment(attachment),
215→      priority,
216→      distance: candidateDistance,
217→    });
218→  };
219→
220→  if (chainStart) {
221→    consider(chainStart, 0, null);
222→  }
223→
224→  for (const wall of walls) {
225→    if (wall.id === ignoreWallId) continue;
226→    consider(wall.start, 1, null);
227→    consider(wall.end, 1, null);
228→  }
229→
230→  for (const column of columns) {
231→    const corners = columnOutline(column);
232→    corners.forEach((corner, index) => {
233→      consider(corner, 2, {
234→        kind: 'column',
235→        columnId: column.id,
236→        featureType: 'corner',
237→        featureIndex: index,
238→      });
239→    });
240→
241→    for (const face of columnFaces(column)) {
242→      consider(face.midpoint, 3, buildFaceAttachment(column, face, face.midpoint));
243→    }
244→
245→    if (directionHint) {
246→      for (const centerline of columnCenterlines(column)) {
247→        if (Math.abs(dot(directionHint, centerline.axis)) < CENTERLINE_ALIGNMENT_THRESHOLD) continue;
248→        const center = columnCenter(column);
249→        const projection = dot(subtract(modelPos, center), centerline.axis);
250→        if (Math.abs(projection) > centerline.halfLength + snapDist) continue;
251→        const point = add(center, scale(centerline.axis, projection));
252→        consider(point, 4, buildCenterlineAttachment(column, centerline, point));
253→      }
254→    }
255→
256→    for (const face of columnFaces(column)) {
257→      const { point } = nearestPointOnSegment(modelPos, face.start, face.end);
258→      consider(point, 5, buildFaceAttachment(column, face, point));
259→    }
260→  }
261→
262→  for (const wall of walls) {
263→    if (wall.id === ignoreWallId) continue;
264→    const { point, t } = nearestPointOnSegment(modelPos, wall.start, wall.end);
265→    if (t <= 0.001 || t >= 0.999) continue;
266→    consider(point, 6, null);
267→  }
268→
269→  if (!best) return null;
270→  return {
271→    point: best.point,
272→    attachment: best.attachment,
273→  };
274→}
275→
276→export function resolveWallEndpoint(wall, endpointKey, columns = []) {
277→  const syncedWall = syncWallAttachmentPoints(wall, columns);
278→  return { ...syncedWall[endpointKey] };
279→}
280→
281→export function resolveWallEndpoints(wall, columns = []) {
282→  const syncedWall = syncWallAttachmentPoints(wall, columns);
283→  return {
284→    start: { ...syncedWall.start },
285→    end: { ...syncedWall.end },
286→    startAttachment: cloneAttachment(syncedWall.startAttachment),
287→    endAttachment: cloneAttachment(syncedWall.endAttachment),
288→  };
289→}
290→
291→export function resolveCenterlineAxis(column, featureIndex) {
292→  const { xAxis, yAxis } = columnAxes(column);
293→  return featureIndex === 1 ? yAxis : xAxis;
294→}
