608→            <p>Doors: {floor.doors.length}</p>
609→            <p>Windows: {floor.windows.length}</p>
610→            <p>Columns: {(floor.columns || []).length}</p>
611→          </>
612→        )}
613→      </div>
614→      {floor && <AnnotationSettingsProperties floor={floor} dispatch={dispatch} />}
615→    </div>
616→  );
617→}
618→
619→export default function PropertiesPanel() {
620→  const { project, dispatch } = useProject();
621→  const { selectedId, selectedType, activeFloorId, dispatch: editorDispatch } = useEditor();
622→  const floor = project.floors.find(f => f.id === activeFloorId);
623→  const u = useUnits();
624→
625→  const handleDelete = () => {
626→    if (!selectedId) return;
627→    if (selectedType === 'slab') {
628→      dispatch({ type: 'SLAB_DELETE', floorId: activeFloorId });
629→    } else if (selectedType === 'wall') {
630→      dispatch({ type: 'WALL_DELETE', floorId: activeFloorId, wallId: selectedId });
631→    } else if (selectedType === 'beam') {
632→      dispatch({ type: 'BEAM_DELETE', floorId: activeFloorId, beamId: selectedId });
633→    } else if (selectedType === 'annotation') {
634→      dispatch({ type: 'ANNOTATION_DELETE', floorId: activeFloorId, annotationId: selectedId });
635→    } else if (selectedType === 'stair') {
636→      dispatch({ type: 'STAIR_DELETE', floorId: activeFloorId, stairId: selectedId });
637→    } else if (selectedType === 'door') {
638→      dispatch({ type: 'DOOR_DELETE', floorId: activeFloorId, doorId: selectedId });
639→    } else if (selectedType === 'window') {
640→      dispatch({ type: 'WINDOW_DELETE', floorId: activeFloorId, windowId: selectedId });
641→    } else if (selectedType === 'column') {
642→      dispatch({ type: 'COLUMN_DELETE', floorId: activeFloorId, columnId: selectedId });
643→    } else if (selectedType === 'room') {
644→      dispatch({ type: 'ROOM_DELETE', floorId: activeFloorId, roomId: selectedId });
645→    }
646→    editorDispatch({ type: 'DESELECT' });
647→  };
648→
649→  let content = <ProjectSummary project={project} floor={floor} dispatch={dispatch} />;
650→
651→  if (selectedId && floor) {
652→    if (selectedType === 'slab') {
653→      if (floor.slab?.id === selectedId) {
654→        content = <SlabProperties slab={floor.slab} floor={floor} dispatch={dispatch} floorId={activeFloorId} u={u} />;
655→      }
656→    } else if (selectedType === 'wall') {
657→      const wall = floor.walls.find(w => w.id === selectedId);
658→      if (wall) {
659→        content = <WallProperties wall={wall} dispatch={dispatch} floorId={activeFloorId} u={u} />;
660→      }
661→    } else if (selectedType === 'beam') {
662→      const beam = (floor.beams || []).find(b => b.id === selectedId);
663→      if (beam) {
664→        content = <BeamProperties beam={beam} floor={floor} dispatch={dispatch} floorId={activeFloorId} u={u} />;
665→      }
666→    } else if (selectedType === 'annotation') {
667→      const annotation = (floor.annotations || []).find((entry) => entry.id === selectedId);
668→      if (annotation) {
669→        content = <AnnotationProperties annotation={annotation} floor={floor} dispatch={dispatch} floorId={activeFloorId} u={u} />;
670→      }
671→    } else if (selectedType === 'stair') {
672→      const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
673→      if (stair) {
674→        content = <StairProperties stair={stair} project={project} dispatch={dispatch} floorId={activeFloorId} u={u} />;
675→      }
676→    } else if (selectedType === 'door') {
677→      const door = floor.doors.find(d => d.id === selectedId);
678→      const wall = door ? floor.walls.find(w => w.id === door.wallId) : null;
679→      if (door) {
680→        content = <DoorProperties door={door} wall={wall} dispatch={dispatch} floorId={activeFloorId} editorDispatch={editorDispatch} u={u} />;
681→      }
682→    } else if (selectedType === 'window') {
683→      const win = floor.windows.find(w => w.id === selectedId);
684→      const wall = win ? floor.walls.find(w => w.id === win.wallId) : null;
685→      if (win) {
686→        content = <WindowProperties window={win} wall={wall} dispatch={dispatch} floorId={activeFloorId} u={u} />;
687→      }
688→    } else if (selectedType === 'column') {
689→      const column = (floor.columns || []).find(c => c.id === selectedId);
690→      if (column) {
691→        content = <ColumnProperties column={column} floor={floor} dispatch={dispatch} floorId={activeFloorId} editorDispatch={editorDispatch} u={u} />;
692→      }
693→    } else if (selectedType === 'room') {
694→      const room = floor.rooms.find(r => r.id === selectedId);
695→      if (room) {
696→        content = <RoomProperties room={room} dispatch={dispatch} floorId={activeFloorId} />;
697→      }
698→    }
699→  }
700→
701→  return (
702→    <div className={styles.panel}>
703→      <div className={styles.unitToggle}>
704→        <span>Units:</span>
705→        <button
706→          className={`${styles.unitBtn} ${u.unit === 'mm' ? styles.unitBtnActive : ''}`}
707→          onClick={() => u.setUnit('mm')}
708→        >mm</button>
709→        <button
710→          className={`${styles.unitBtn} ${u.unit === 'm' ? styles.unitBtnActive : ''}`}
711→          onClick={() => u.setUnit('m')}
712→        >m</button>
713→      </div>
714→      {content}
715→      {selectedId && (
716→        <button className={styles.deleteBtn} onClick={handleDelete}>
717→          Delete {selectedType}
718→        </button>
719→      )}
720→    </div>
721→  );
722→}
