  1→import { createAnnotationSettings } from '@/domain/models';
  2→import { createDimensionFigure } from '@/annotations/dimensions';
  3→
  4→const EPSILON = 5;
  5→const OVERALL_WIDTH_OFFSET = 700;
  6→const OVERALL_HEIGHT_OFFSET = -900;
  7→const LEVEL_OFFSET_START = -1400;
  8→const LEVEL_OFFSET_STEP = -350;
  9→const OPENING_HEIGHT_OFFSET = 260;
 10→const OPENING_SILL_OFFSET = 560;
 11→const OPENING_HEAD_OFFSET = 860;
 12→
 13→function toElevationPoint(x, z) {
 14→  return { x, y: -z };
 15→}
 16→
 17→function uniqueSortedValues(values = []) {
 18→  const sorted = [...values].sort((a, b) => a - b);
 19→  return sorted.filter((value, index) => (
 20→    index === 0 || Math.abs(value - sorted[index - 1]) > EPSILON
 21→  ));
 22→}
 23→
 24→function createVerticalDimension(id, x, startZ, endZ, offset, sourceType, sourceId) {
 25→  return createDimensionFigure({
 26→    id,
 27→    startPoint: toElevationPoint(x, startZ),
 28→    endPoint: toElevationPoint(x, endZ),
 29→    mode: 'vertical',
 30→    offset,
 31→    source: 'derived',
 32→    sourceType,
 33→    sourceId,
 34→  });
 35→}
 36→
 37→function buildOverallDimensions(scene) {
 38→  if (!scene?.elements?.length) return [];
 39→
 40→  const overallWidth = createDimensionFigure({
 41→    id: `${scene.viewKey}-overall-width`,
 42→    startPoint: toElevationPoint(scene.bounds.minX, scene.groundLevel),
 43→    endPoint: toElevationPoint(scene.bounds.maxX, scene.groundLevel),
 44→    mode: 'horizontal',
 45→    offset: OVERALL_WIDTH_OFFSET,
 46→    source: 'derived',
 47→    sourceType: 'elevation-overall',
 48→  });
 49→
 50→  const overallHeight = createVerticalDimension(
 51→    `${scene.viewKey}-overall-height`,
 52→    scene.bounds.minX,
 53→    scene.groundLevel,
 54→    scene.bounds.maxZ,
 55→    OVERALL_HEIGHT_OFFSET,
 56→    'elevation-overall',
 57→    null
 58→  );
 59→
 60→  return [overallWidth, overallHeight].filter(Boolean);
 61→}
 62→
 63→function buildLevelDimensions(scene) {
 64→  if (!scene?.elements?.length) return [];
 65→
 66→  const levelValues = [];
 67→  for (const element of scene.elements) {
 68→    if (element.category === 'slab' || element.category === 'beam') {
 69→      levelValues.push(element.bottom, element.top);
 70→    }
 71→  }
 72→
 73→  return uniqueSortedValues(levelValues)
 74→    .filter((value) => Math.abs(value - scene.groundLevel) > EPSILON)
 75→    .map((value, index) => createVerticalDimension(
 76→      `${scene.viewKey}-level-${index}`,
 77→      scene.bounds.minX,
 78→      scene.groundLevel,
 79→      value,
 80→      LEVEL_OFFSET_START + (LEVEL_OFFSET_STEP * index),
 81→      'elevation-level',
 82→      null
 83→    ))
 84→    .filter(Boolean);
 85→}
 86→
 87→function buildOpeningDimensions(scene) {
 88→  if (!scene?.elements?.length) return [];
 89→
 90→  const figures = [];
 91→  const openings = scene.elements.filter((element) => (
 92→    element.category === 'door' || element.category === 'window'
 93→  ));
 94→
 95→  for (const opening of openings) {
 96→    const idPrefix = `${scene.viewKey}-${opening.category}-${opening.sourceId || opening.id}`;
 97→
 98→    const heightFigure = createVerticalDimension(
 99→      `${idPrefix}-height`,
100→      opening.right,
101→      opening.bottom,
102→      opening.top,
103→      OPENING_HEIGHT_OFFSET,
104→      'elevation-opening-height',
105→      opening.sourceId
106→    );
107→    if (heightFigure) figures.push(heightFigure);
108→
109→    if (Math.abs(opening.bottom - scene.groundLevel) > EPSILON) {
110→      const sillFigure = createVerticalDimension(
111→        `${idPrefix}-sill`,
112→        opening.left,
113→        scene.groundLevel,
114→        opening.bottom,
115→        OPENING_SILL_OFFSET,
116→        'elevation-opening-sill',
117→        opening.sourceId
118→      );
119→      if (sillFigure) figures.push(sillFigure);
120→
121→      const headFigure = createVerticalDimension(
122→        `${idPrefix}-head`,
123→        opening.left,
124→        scene.groundLevel,
125→        opening.top,
126→        OPENING_HEAD_OFFSET,
127→        'elevation-opening-head',
128→        opening.sourceId
129→      );
130→      if (headFigure) figures.push(headFigure);
131→    }
132→  }
133→
134→  return figures;
135→}
136→
137→function resolveSettings(floor) {
138→  return createAnnotationSettings(floor?.annotationSettings || {});
139→}
140→
141→export function buildElevationAnnotationScene(floor, scene) {
142→  if (!floor || !scene) {
143→    return {
144→      dimensions: [],
145→    };
146→  }
147→
148→  const settings = resolveSettings(floor);
149→  const dimensions = [
150→    ...(settings.showElevationOverallDimensions ? buildOverallDimensions(scene) : []),
151→    ...(settings.showElevationLevelDimensions ? buildLevelDimensions(scene) : []),
152→    ...(settings.showElevationOpeningDimensions ? buildOpeningDimensions(scene) : []),
153→  ];
154→
155→  return { dimensions };
156→}
